   242→  // Helper to keep cache callbacks wait flags consistent
   243→  class AutoCacheWaitFlags {
   244→   public:
   245→    explicit AutoCacheWaitFlags(nsHttpChannel* channel)
   246→        : mChannel(channel), mKeep(0) {
   247→      // Flags must be set before entering any AsyncOpenCacheEntry call.
   248→      mChannel->StoreWaitForCacheEntry(nsHttpChannel::WAIT_FOR_CACHE_ENTRY);
   249→    }
   250→
   251→    void Keep(uint32_t flags) {
   252→      // Called after successful call to appropriate AsyncOpenCacheEntry call.
   253→      mKeep |= flags;
   254→    }
   255→
   256→    ~AutoCacheWaitFlags() {
   257→      // Keep only flags those are left to be wait for.
   258→      mChannel->StoreWaitForCacheEntry(mChannel->LoadWaitForCacheEntry() &
   259→                                       mKeep);
   260→    }
   261→
   262→   private:
   263→    nsHttpChannel* mChannel;
   264→    uint32_t mKeep : 1;
   265→  };
