   946→  nsMainThreadPtrHandle<nsIReplacedHttpResponse> mOverrideResponse;
   947→  // LNA telemetry: stores the user's action on the permission prompt
   948→  // Values: "allow", "deny", or empty string (no prompt shown)
   949→  nsCString mLNAPromptAction;
   950→};
   951→
   952→}  // namespace net
   953→}  // namespace mozilla
   954→
   955→inline nsISupports* ToSupports(mozilla::net::nsHttpChannel* aChannel) {
   956→  return static_cast<nsIHttpChannel*>(aChannel);
   957→}
   958→
   959→#endif  // nsHttpChannel_h_
